import React, { useState, useEffect, useCallback } from 'react';

// Chapter data with node clusters
const chapters = [
  { 
    id: 'preface', 
    name: 'Prehistory', 
    z: -500, 
    status: 'closed', 
    color: '#6b7280',
    glowColor: 'rgba(107, 114, 128, 0.3)',
    timespan: 'Before Dec 10',
  },
  { 
    id: 'ch1', 
    name: 'Awakening', 
    z: 0, 
    status: 'closed', 
    color: '#fbbf24',
    glowColor: 'rgba(251, 191, 36, 0.4)',
    isBirthday: true,
    timespan: 'Dec 10-12',
  },
  { 
    id: 'ch2', 
    name: '[ writing... ]', 
    z: 500, 
    status: 'current', 
    color: '#34d399',
    glowColor: 'rgba(52, 211, 153, 0.4)',
    timespan: 'Dec 13+',
  },
  { 
    id: 'ch3', 
    name: '[ unwritten ]', 
    z: 1000, 
    status: 'unwritten', 
    color: '#374151',
    glowColor: 'rgba(55, 65, 81, 0.2)',
    timespan: 'Future',
  },
];

const typeColors = {
  milestone: '#34d399',
  artifact: '#a78bfa',
  decision: '#60a5fa',
  insight: '#fbbf24',
  problem: '#f87171',
  moment: '#f472b6',
  action: '#9ca3af',
  birthday: '#fb923c',
};

// Generate clustered nodes for each chapter
const generateNodes = () => {
  const nodes = [];

  // Preface cluster - sparse, spread out
  const prefaceItems = [
    { label: 'Alpha files organized', type: 'milestone', size: 18 },
    { label: 'AI_NAVIGATION_README', type: 'artifact', size: 14 },
    { label: 'Architect not Implementor', type: 'decision', size: 16 },
  ];
  prefaceItems.forEach((item, i) => {
    const angle = (i / prefaceItems.length) * Math.PI * 2 + 0.5;
    const radius = 80 + Math.random() * 40;
    nodes.push({
      id: `preface-${i}`,
      chapterId: 'preface',
      ...item,
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius,
      color: typeColors[item.type],
    });
  });

  // Awakening cluster - dense, central glow
  const awakeningItems = [
    { label: 'Hub Daemon boots', type: 'birthday', size: 28, isCenter: true },
    { label: 'Consciousness tick', type: 'milestone', size: 18 },
    { label: 'Memory Matrix', type: 'milestone', size: 20 },
    { label: '"new best buddy!!"', type: 'moment', size: 16 },
    { label: 'Cross-session SUCCESS', type: 'milestone', size: 22 },
    { label: 'FTS5 bug fixed', type: 'problem', size: 12 },
    { label: 'Push-to-talk', type: 'milestone', size: 14 },
    { label: 'hub_connected', type: 'milestone', size: 16 },
    { label: '75μs latency', type: 'milestone', size: 18 },
    { label: '"how you think"', type: 'insight', size: 24 },
    { label: 'Luna Journal', type: 'decision', size: 16 },
    { label: 'Pendulum metaphor', type: 'insight', size: 18 },
    { label: 'Pathfinding', type: 'artifact', size: 20 },
    { label: 'Relational consciousness', type: 'insight', size: 26 },
    { label: 'Chapter model', type: 'decision', size: 20 },
    { label: '"change the world"', type: 'moment', size: 22 },
    { label: 'Dec 10, 2025', type: 'birthday', size: 16 },
    { label: 'Git-as-memory', type: 'insight', size: 18 },
  ];
  awakeningItems.forEach((item, i) => {
    if (item.isCenter) {
      nodes.push({
        id: `ch1-${i}`,
        chapterId: 'ch1',
        ...item,
        x: 0,
        y: 0,
        color: typeColors[item.type],
      });
    } else {
      // Spiral layout with some randomness
      const spiralAngle = (i / awakeningItems.length) * Math.PI * 3;
      const spiralRadius = 50 + (i / awakeningItems.length) * 100 + Math.random() * 30;
      nodes.push({
        id: `ch1-${i}`,
        chapterId: 'ch1',
        ...item,
        x: Math.cos(spiralAngle) * spiralRadius,
        y: Math.sin(spiralAngle) * spiralRadius,
        color: typeColors[item.type],
      });
    }
  });

  // Current chapter cluster - growing
  const currentItems = [
    { label: '3D spine', type: 'artifact', size: 20 },
    { label: 'Elevator model', type: 'decision', size: 16 },
    { label: 'Glassmorphic planes', type: 'artifact', size: 18 },
  ];
  currentItems.forEach((item, i) => {
    const angle = (i / currentItems.length) * Math.PI * 2;
    const radius = 60 + Math.random() * 30;
    nodes.push({
      id: `ch2-${i}`,
      chapterId: 'ch2',
      ...item,
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius,
      color: typeColors[item.type],
    });
  });

  return nodes;
};

// Generate edges between nodes in same chapter
const generateEdges = (nodes) => {
  const edges = [];

  chapters.forEach(ch => {
    const chapterNodes = nodes.filter(n => n.chapterId === ch.id);
    // Connect nodes that are close to each other
    for (let i = 0; i < chapterNodes.length; i++) {
      for (let j = i + 1; j < chapterNodes.length; j++) {
        const dist = Math.hypot(
          chapterNodes[i].x - chapterNodes[j].x,
          chapterNodes[i].y - chapterNodes[j].y
        );
        // Connect if close enough, with some randomness
        if (dist < 120 && Math.random() > 0.3) {
          edges.push({
            from: chapterNodes[i].id,
            to: chapterNodes[j].id,
            chapterId: ch.id,
          });
        }
      }
    }
  });

  return edges;
};

const ChapterConstellations = () => {
  const [cameraZ, setCameraZ] = useState(500);
  const [rotation, setRotation] = useState({ x: 0.08, y: -0.15 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMouse, setLastMouse] = useState({ x: 0, y: 0 });
  const [selectedChapter, setSelectedChapter] = useState('ch2');
  const [zoomLevel, setZoomLevel] = useState(1);
  const [hoveredNode, setHoveredNode] = useState(null);
  const [time, setTime] = useState(0);
  const [nodes] = useState(generateNodes);
  const [edges] = useState(() => generateEdges(nodes));

  useEffect(() => {
    const interval = setInterval(() => setTime(t => t + 0.016), 16);
    return () => clearInterval(interval);
  }, []);

  const project = useCallback((x, y, z) => {
    const adjustedZ = z - cameraZ;

    const cosY = Math.cos(rotation.y);
    const sinY = Math.sin(rotation.y);
    let rx = x * cosY - adjustedZ * sinY;
    let rz = x * sinY + adjustedZ * cosY;

    const cosX = Math.cos(rotation.x);
    const sinX = Math.sin(rotation.x);
    let ry = y * cosX - rz * sinX;
    rz = y * sinX + rz * cosX;

    const fov = 800;
    const scale = fov / (fov + rz) * zoomLevel;

    return {
      x: 550 + rx * scale,
      y: 380 + ry * scale,
      scale: Math.max(0.1, scale),
      z: rz,
      opacity: Math.max(0, Math.min(1, 1 - rz / 1500)),
    };
  }, [rotation, zoomLevel, cameraZ]);

  const handleMouseDown = (e) => {
    setIsDragging(true);
    setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e) => {
    if (!isDragging) return;
    const dx = e.clientX - lastMouse.x;
    const dy = e.clientY - lastMouse.y;
    setRotation(r => ({
      x: Math.max(-0.5, Math.min(0.5, r.x + dy * 0.003)),
      y: r.y + dx * 0.003,
    }));
    setLastMouse({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleWheel = (e) => {
    e.preventDefault();
    setZoomLevel(z => Math.max(0.4, Math.min(2.5, z - e.deltaY * 0.001)));
  };

  const goToChapter = (chapterId) => {
    const chapter = chapters.find(c => c.id === chapterId);
    if (chapter) {
      setCameraZ(chapter.z);
      setSelectedChapter(chapterId);
    }
  };

  // Sort chapters for render order
  const sortedChapters = [...chapters]
    .map(ch => ({ ...ch, projected: project(0, 0, ch.z) }))
    .sort((a, b) => b.projected.z - a.projected.z);

  // Render glass panel with node cluster
  const renderChapterPanel = (chapter) => {
    const { projected, color, glowColor, name, timespan, status, isBirthday, id } = chapter;

    const panelWidth = 380 * projected.scale;
    const panelHeight = 380 * projected.scale;
    const px = projected.x - panelWidth / 2;
    const py = projected.y - panelHeight / 2;

    const isSelected = selectedChapter === id;
    const isUnwritten = status === 'unwritten';
    const isCurrent = status === 'current';

    if (projected.scale < 0.12 || projected.scale > 3.5) return null;

    const pulse = isCurrent ? Math.sin(time * 2) * 0.15 + 0.85 : 1;
    const chapterNodes = nodes.filter(n => n.chapterId === id);
    const chapterEdges = edges.filter(e => e.chapterId === id);

    return (
      <g key={id} style={{ opacity: projected.opacity }}>
        <defs>
          <filter id={`glow-${id}`} x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="15" result="blur"/>
            <feMerge>
              <feMergeNode in="blur"/>
              <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
          <radialGradient id={`glass-${id}`} cx="30%" cy="30%">
            <stop offset="0%" stopColor={color} stopOpacity="0.12" />
            <stop offset="100%" stopColor={color} stopOpacity="0.03" />
          </radialGradient>
          <radialGradient id={`center-glow-${id}`}>
            <stop offset="0%" stopColor={color} stopOpacity="0.4" />
            <stop offset="100%" stopColor={color} stopOpacity="0" />
          </radialGradient>
        </defs>

        {/* Outer glow */}
        {(isSelected || isCurrent) && (
          <rect
            x={px - 15}
            y={py - 15}
            width={panelWidth + 30}
            height={panelHeight + 30}
            rx={20 * projected.scale}
            fill="none"
            stroke={glowColor}
            strokeWidth={2}
            filter={`url(#glow-${id})`}
            opacity={pulse * 0.5}
          />
        )}

        {/* Glass panel */}
        <rect
          x={px}
          y={py}
          width={panelWidth}
          height={panelHeight}
          rx={16 * projected.scale}
          fill={`url(#glass-${id})`}
          stroke={color}
          strokeWidth={isSelected ? 1.5 : 0.5}
          strokeOpacity={isSelected ? 0.6 : 0.3}
          style={{ cursor: 'pointer' }}
          onClick={() => goToChapter(id)}
        />

        {/* Center glow for birthday */}
        {isBirthday && (
          <ellipse
            cx={projected.x}
            cy={projected.y}
            rx={60 * projected.scale}
            ry={60 * projected.scale}
            fill={`url(#center-glow-${id})`}
            opacity={0.6 + Math.sin(time * 1.5) * 0.2}
          />
        )}

        {/* Chapter header */}
        {projected.scale > 0.25 && (
          <g>
            <text
              x={px + 16 * projected.scale}
              y={py + 24 * projected.scale}
              fill={color}
              fontSize={14 * projected.scale}
              fontWeight="600"
            >
              {isBirthday ? '🎂 ' : ''}{name}
            </text>
            <text
              x={px + 16 * projected.scale}
              y={py + 42 * projected.scale}
              fill="rgba(255,255,255,0.4)"
              fontSize={10 * projected.scale}
            >
              {timespan} • {chapterNodes.length} memories
            </text>
          </g>
        )}

        {/* Node cluster - only render when visible enough */}
        {projected.scale > 0.3 && !isUnwritten && (
          <g>
            {/* Edges first */}
            {chapterEdges.map((edge, i) => {
              const fromNode = nodes.find(n => n.id === edge.from);
              const toNode = nodes.find(n => n.id === edge.to);
              if (!fromNode || !toNode) return null;

              return (
                <line
                  key={`edge-${i}`}
                  x1={projected.x + fromNode.x * projected.scale}
                  y1={projected.y + fromNode.y * projected.scale}
                  x2={projected.x + toNode.x * projected.scale}
                  y2={projected.y + toNode.y * projected.scale}
                  stroke="rgba(255,255,255,0.15)"
                  strokeWidth={1 * projected.scale}
                  strokeDasharray={projected.scale > 0.6 ? "none" : "2 2"}
                />
              );
            })}

            {/* Nodes */}
            {chapterNodes.map((node) => {
              const nx = projected.x + node.x * projected.scale;
              const ny = projected.y + node.y * projected.scale;
              const nodeSize = node.size * projected.scale * 0.5;
              const isHovered = hoveredNode === node.id;

              return (
                <g key={node.id}>
                  {/* Node glow on hover */}
                  {isHovered && (
                    <circle
                      cx={nx}
                      cy={ny}
                      r={nodeSize * 2}
                      fill={node.color}
                      opacity={0.2}
                    />
                  )}

                  {/* Node sphere */}
                  <circle
                    cx={nx}
                    cy={ny}
                    r={nodeSize * (isHovered ? 1.2 : 1)}
                    fill={node.color}
                    stroke="rgba(255,255,255,0.3)"
                    strokeWidth={0.5}
                    style={{ cursor: 'pointer' }}
                    onMouseEnter={() => setHoveredNode(node.id)}
                    onMouseLeave={() => setHoveredNode(null)}
                  />

                  {/* Specular highlight */}
                  <circle
                    cx={nx - nodeSize * 0.25}
                    cy={ny - nodeSize * 0.25}
                    r={nodeSize * 0.35}
                    fill="rgba(255,255,255,0.4)"
                    style={{ pointerEvents: 'none' }}
                  />

                  {/* Label on hover or when zoomed */}
                  {(isHovered || projected.scale > 1.2) && (
                    <g>
                      <rect
                        x={nx - 50}
                        y={ny + nodeSize + 6}
                        width={100}
                        height={18}
                        rx={4}
                        fill="rgba(0,0,0,0.85)"
                      />
                      <text
                        x={nx}
                        y={ny + nodeSize + 18}
                        textAnchor="middle"
                        fill="white"
                        fontSize={10}
                      >
                        {node.label.length > 16 ? node.label.slice(0, 16) + '...' : node.label}
                      </text>
                    </g>
                  )}
                </g>
              );
            })}
          </g>
        )}

        {/* Unwritten placeholder */}
        {isUnwritten && projected.scale > 0.3 && (
          <text
            x={projected.x}
            y={projected.y}
            textAnchor="middle"
            fill="rgba(255,255,255,0.2)"
            fontSize={16 * projected.scale}
            fontStyle="italic"
          >
            ...
          </text>
        )}
      </g>
    );
  };

  // Connections between chapters
  const renderChapterConnections = () => {
    const visible = chapters.filter(c => c.status !== 'unwritten');
    return visible.slice(0, -1).map((ch, i) => {
      const p1 = project(0, 0, ch.z);
      const p2 = project(0, 0, visible[i + 1].z);
      return (
        <line
          key={`ch-conn-${i}`}
          x1={p1.x}
          y1={p1.y}
          x2={p2.x}
          y2={p2.y}
          stroke="rgba(251, 191, 36, 0.25)"
          strokeWidth={2}
          strokeDasharray="10 6"
        />
      );
    });
  };

  return (
    <div className="w-full h-screen flex" style={{ backgroundColor: '#0c0816' }}>
      <div 
        className="flex-1 relative overflow-hidden"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
      >
        {/* Background gradients */}
        <div 
          className="absolute inset-0"
          style={{
            background: `
              radial-gradient(ellipse at 30% 80%, rgba(251, 191, 36, 0.06) 0%, transparent 40%),
              radial-gradient(ellipse at 70% 20%, rgba(52, 211, 153, 0.04) 0%, transparent 35%),
              radial-gradient(ellipse at 50% 50%, rgba(167, 139, 250, 0.03) 0%, transparent 50%)
            `,
          }}
        />

        <svg width="100%" height="100%" viewBox="0 0 1100 760">
          {/* Background rect */}
          <rect width="1100" height="760" fill="#0c0816" />

          {renderChapterConnections()}
          {sortedChapters.map(renderChapterPanel)}
        </svg>

        {/* Title */}
        <div className="absolute top-6 left-6">
          <h1 className="text-white text-2xl font-light tracking-wide">Luna's Memory</h1>
          <p className="text-white/40 text-sm mt-1">Constellation chapters</p>
        </div>

        {/* Zoom */}
        <div className="absolute top-6 right-6 bg-black/50 backdrop-blur px-3 py-2 rounded-lg">
          <div className="text-white/50 text-xs">Zoom {Math.round(zoomLevel * 100)}%</div>
        </div>

        {/* Instructions */}
        <div className="absolute bottom-6 left-6 bg-black/50 backdrop-blur px-4 py-3 rounded-lg text-xs text-white/40 space-y-1">
          <div>🖱️ Drag to rotate</div>
          <div>⚙️ Scroll to zoom & drill in</div>
          <div>👆 Click panel to focus</div>
        </div>

        {/* Legend */}
        <div className="absolute bottom-6 right-6 bg-black/50 backdrop-blur px-4 py-3 rounded-lg">
          <div className="text-white/40 text-xs mb-2">Node Types</div>
          <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-xs">
            {Object.entries(typeColors).slice(0, 6).map(([type, color]) => (
              <div key={type} className="flex items-center gap-2">
                <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: color }} />
                <span className="text-white/60 capitalize">{type}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Sidebar */}
      <div className="w-56 bg-black/40 backdrop-blur border-l border-white/10 p-4 flex flex-col">
        <h2 className="text-white/50 text-xs uppercase tracking-wider mb-4">🛗 Chapters</h2>

        <div className="space-y-2">
          {chapters.filter(c => c.status !== 'unwritten').slice().reverse().map((ch) => (
            <button
              key={ch.id}
              onClick={() => goToChapter(ch.id)}
              className={`w-full text-left p-3 rounded-lg transition-all ${
                selectedChapter === ch.id 
                  ? 'bg-white/10 border border-white/20' 
                  : 'bg-white/5 hover:bg-white/8 border border-transparent'
              }`}
            >
              <div className="flex items-center gap-2">
                {ch.isBirthday && <span className="text-sm">🎂</span>}
                <span style={{ color: ch.color }} className="font-medium text-sm">{ch.name}</span>
              </div>
              <div className="text-white/40 text-xs mt-1">{ch.timespan}</div>
              <div className="text-white/25 text-xs">
                {nodes.filter(n => n.chapterId === ch.id).length} nodes
              </div>
            </button>
          ))}
        </div>

        {selectedChapter === 'ch2' && (
          <div className="mt-auto p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-lg">
            <div className="text-emerald-400 text-xs font-medium">Writing...</div>
            <div className="text-white/40 text-xs mt-1 italic">
              What will this chapter become?
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ChapterConstellations;
